mapper.select:
SELECT count(*) AS user_count
  FROM TC_USER a
 WHERE a.USER_EMAIL = #{userEmail}

SELECT a.user_id, a.user_nm, a.user_email, a.user_position_nm, a.user_phone_mobile, a.user_phone_office, a.dept_cd, a.user_dept_nm, b.company_nm, b.company_cd, b.department_nm, b.department_cd, b.comp_type_cd FROM TC_USER a LEFT JOIN v_organization_structure b ON a.dept_cd = b.origin_cd LEFT JOIN tc_auth_group_user c ON a.user_id = c.user_id WHERE a.DELETE_YN = 'N' AND a.USER_EMAIL IS NOT NULL AND a.USER_EMAIL != ''
AND a.dept_cd = #{deptCode}
AND a.dept_cd != #{deptCode}
AND c.group_cd IN (#{userGroup}, #{deptManageGroup}) GROUP BY a.user_id, a.user_email ORDER BY b.department_nm DESC, a.user_nm DESC

mapper.insert:
INSERT INTO TC_COMMON_HISTORY (
    TARGET_ID, MENU_CD, HIS_DT, HIS_TYPE_CD, HIS_CONTENTS, USER_ID, FILE_ID
) VALUES (
    #{userId}, #{menuCd}, NOW(), #{hisTypeCd}, #{hisContents}, 'SYSTEM', NULL
)

mapper.select:
GROUP BY u.USER_ID, u.USER_NM, u.USER_EMAIL, u.DELETE_YN, u.USER_DEPT_NM, u.DEPT_CD, u.USER_POSITION_NM, u.USER_PHONE_OFFICE, u.USER_PHONE_MOBILE, u.REMARK, u.USER_CERT_YN, u.USER_CONSENT_YN, u.REG_DT, d.COMPANY_NM, d.DEPARTMENT_NM, d.MANAGE_NM
ORDER BY ${criteria} ${sort}
ORDER BY u.REG_DT DESC
LIMIT #{pageSize} OFFSET #{offset}
